package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.OutputStreamWriter;
import java.nio.charset.Charset;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws Exception {
        // Given
        File file = new File("test.csv");
        Charset charset = Charset.defaultCharset();
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVPrinter csvPrinterMock = mock(CSVPrinter.class);
        CSVFormat spyCsvFormat = spy(csvFormat);

        OutputStreamWriter outputStreamWriterMock = mock(OutputStreamWriter.class);
        whenNew(OutputStreamWriter.class).withArguments(any(FileOutputStream.class), eq(charset))
                .thenReturn(outputStreamWriterMock);

        whenNew(CSVPrinter.class).withArguments(outputStreamWriterMock, spyCsvFormat)
                .thenReturn(csvPrinterMock);

        // When
        CSVPrinter result = spyCsvFormat.print(file, charset);

        // Then
        assertEquals(csvPrinterMock, result);
        verifyNew(OutputStreamWriter.class).withArguments(any(FileOutputStream.class), eq(charset));
        verifyNew(CSVPrinter.class).withArguments(outputStreamWriterMock, spyCsvFormat);
    }
}
